// signal.service.ts
import { Injectable, signal } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class MasterSignalService {
    private _masterTabName = signal<string>(''); // private signal

    // Getter for signal
    readonly masterTabName = this._masterTabName;

    // Setter
    setMasterTabName(name: string) {
        this._masterTabName.set(name);
    }
}